import sys
from itertools import combinations
from functools import lru_cache

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    H = int(data[1])
    W = int(data[2])
    tiles = []
    idx = 3
    for _ in range(N):
        a = int(data[idx])
        b = int(data[idx + 1])
        tiles.append((a, b))
        idx += 2

    total_area = H * W

    # Generate all possible subsets of tiles
    for k in range(1, N + 1):
        for subset in combinations(tiles, k):
            subset_area = sum(a * b for a, b in subset)
            if subset_area == total_area:
                # Try to place this subset of tiles
                if can_place(subset, H, W):
                    print("Yes")
                    return
    print("No")

def can_place(tiles, H, W):
    from collections import deque

    def dfs(remaining, grid):
        if not remaining:
            return True
        tile = remaining[0]
        a, b = tile
        for i in range(H):
            for j in range(W):
                if grid[i][j] == 0:
                    # Try placing the tile in original orientation
                    if i + a <= H and j + b <= W:
                        valid = True
                        for x in range(i, i + a):
                            for y in range(j, j + b):
                                if grid[x][y] != 0:
                                    valid = False
                                    break
                            if not valid:
                                break
                        if valid:
                            new_grid = [row[:] for row in grid]
                            for x in range(i, i + a):
                                for y in range(j, j + b):
                                    new_grid[x][y] = 1
                            if dfs(remaining[1:], new_grid):
                                return True
                    # Try placing the tile in rotated orientation
                    if i + b <= H and j + a <= W:
                        valid = True
                        for x in range(i, i + b):
                            for y in range(j, j + a):
                                if grid[x][y] != 0:
                                    valid = False
                                    break
                            if not valid:
                                break
                        if valid:
                            new_grid = [row[:] for row in grid]
                            for x in range(i, i + b):
                                for y in range(j, j + a):
                                    new_grid[x][y] = 1
                            if dfs(remaining[1:], new_grid):
                                return True
        return False

    initial_grid = [[0 for _ in range(W)] for _ in range(H)]
    return dfs(tiles, initial_grid)

main()
